refentry.refsect1:
&reftitle.returnvalues;

 Devuelve &true; si no hay definitivamente más resultados disponibles en el
 cursor, y &false; en caso contrario.

  &reftitle.examples;

   Ejemplo de MongoDB\Driver\Cursor::isDead


<?php

$manager = new MongoDB\Driver\Manager("mongodb://localhost:27017");
$query = new MongoDB\Driver\Query([]);

$bulk = new MongoDB\Driver\BulkWrite;
$bulk->insert(['x' => 1]);
$bulk->insert(['x' => 2]);
$bulk->insert(['x' => 3]);
$manager->executeBulkWrite('db.collection', $bulk);

$cursor = $manager->executeQuery('db.collection', $query);

$iterator = new IteratorIterator($cursor);

$iterator->rewind();
var_dump($cursor->isDead());

$iterator->next();
var_dump($cursor->isDead());

$iterator->next();
var_dump($cursor->isDead());

$iterator->next();
var_dump($cursor->isDead());

?>


   &example.outputs;


bool(false)
bool(false)
bool(false)
bool(true)

&reftitle.seealso;

 Cursores persistentes en el manual de MongoDB
